"use strict";
module.exports = /*#__PURE__*/JSON.parse('[{"id":"fsb-major","pickerLabel":"Мне позвонили и представились сотрудником ФСБ / ЦБ","emoji":"🔐","title":"Звонок от «майора ФСБ»","subtitle":"Проверьте, на каком шаге вы бы остановились","description":"Вам звонит сотрудник ФСБ и сообщает, что на ваше имя оформлен кредит. Пройдите сценарий и проверьте, распознаете ли вы мошенника.","source":"По материалам sam.mos.ru и gazprombank.ru","steps":[{"id":1,"question":"Вам позвонили с незнакомого номера. Вы взяли трубку?","options":[{"text":"Да, взял","color":"red"},{"text":"Нет, сбросил","color":"green"}],"explain":{"red":"Незнакомый номер — первый звоночек. Но мошенники умеют подменять номера на знакомые, поэтому даже опытные люди могут ошибиться.","green":"Вы сбросили — и правильно. Однако помните: мошенники могут звонить с номеров, похожих на официальные, так что всегда перезванивайте сами."}},{"id":2,"question":"Звонящий представился майором ФСБ Ивановым и назвал ваши паспортные данные. Вы поверили?","options":[{"text":"Да, поверил","color":"red"},{"text":"Нет, усомнился","color":"green"}],"explain":{"red":"Паспортные данные часто утекают в сеть — это не доказательство. Сотрудники ФСБ не звонят гражданам по таким вопросам.","green":"Правильно. Любые персональные данные можно найти в утечках, это не повод доверять незнакомцу."}},{"id":3,"question":"Он сказал, что на ваше имя оформлен кредит, и предложил «помочь» следствию. Вы согласились сотрудничать?","options":[{"text":"Да, согласился","color":"red"},{"text":"Нет, отказался","color":"green"}],"explain":{"red":"Никакой «помощи следствию» не существует. Это классический приём — втереться в доверие через «общее дело».","green":"Отличная реакция. Настоящие сотрудники никогда не просят граждан участвовать в оперативных мероприятиях."}},{"id":4,"question":"Он попросил установить приложение для удалённого доступа на ваш телефон. Вы согласились?","options":[{"text":"Да, установил","color":"red"},{"text":"Нет, отказался","color":"green"}],"explain":{"red":"Приложения удалённого доступа дают мошенникам полный контроль над вашим телефоном и банком. Никогда не устанавливайте их по просьбе незнакомцев.","green":"Верное решение. Удалённый доступ — это ключи к вашим счетам, фото, контактам и СМС."}},{"id":5,"question":"Он попросил назвать код из СМС-сообщения. Вы назвали?","options":[{"text":"Да, назвал","color":"red"},{"text":"Нет, не назвал","color":"green"}],"explain":{"red":"Код из СМС — это фактически подпись для операции. Называя его, вы даёте доступ к своим деньгам. Настоящие сотрудники никогда не просят коды.","green":"Абсолютно верно. Код из СМС, CVV и ПИН-код — тайна, которую нельзя сообщать никому."}},{"id":6,"question":"Он попросил перевести деньги на «безопасный счёт». Вы перевели?","options":[{"text":"Да, перевёл","color":"red"},{"text":"Нет, не перевёл","color":"green"}],"explain":{"red":"«Безопасных счетов» не существует. Это деньги мошенников. ЦБ, ФСБ и МВД никогда не просят переводить деньги на «специальные счета».","green":"Блестяще. Вы прошли всю схему, не попавшись. Помните: безопасных счетов не существует, кто бы вам ни звонил."}}],"verdicts":[{"minRed":0,"maxRed":1,"title":"Вы почти неуязвимы","text":"Вы прошли схему «Майор ФСБ», практически не поведясь. Вы отлично знаете основные признаки мошенничества. Поделитесь этой карточкой с близкими — им тоже важно быть начеку."},{"minRed":2,"maxRed":3,"title":"Вы в зоне риска","text":"Вы прошли половину шагов в красной зоне. В реальности вас могло спасти только чудо или случайный звонок в банк. Выучите главное правило: ФСБ и ЦБ никогда не звонят гражданам."},{"minRed":4,"maxRed":6,"title":"Вы бы потеряли деньги","text":"Вы прошли почти весь путь жертвы. Мошенники очень убедительны, но запомните: сотрудники ФСБ и банков никогда не просят коды, переводы или установку приложений. Будьте внимательны!"}]},{"id":"safe-account","pickerLabel":"Мне позвонили из банка и попросили перевести деньги на безопасный счёт","emoji":"🏦","title":"Безопасный счёт","subtitle":"Проверьте, сможете ли вы сохранить свои деньги","description":"«Сотрудник банка» убеждает вас перевести все деньги на защищённый счёт. Сможете ли вы вовремя распознать обман?","source":"По материалам cbr.ru и mos.ru","steps":[{"id":1,"question":"Вам пришло СМС от «банка» о подозрительном входе в личный кабинет. Вы перешли по ссылке из сообщения?","options":[{"text":"Да, перешёл","color":"red"},{"text":"Нет, проигнорировал","color":"green"}],"explain":{"red":"Ссылки из подозрительных СМС ведут на фишинговые сайты. Всегда заходите в банк через официальное приложение или набирайте адрес вручную.","green":"Правильно. Любые ссылки из СМС — риск. Лучше открыть приложение банка отдельно и проверить информацию там."}},{"id":2,"question":"Сайт выглядел как настоящий, но URL отличался. Вы ввели свои логин и пароль?","options":[{"text":"Да, ввёл","color":"red"},{"text":"Нет, заметил подмену","color":"green"}],"explain":{"red":"Фишинговые сайты копируют дизайн банков, но URL всегда отличается. Теперь мошенники имеют ваш логин и пароль.","green":"Отлично. Проверка URL — важнейшая привычка. Банки используют защищённые протоколы и не рассылают ссылки в СМС."}},{"id":3,"question":"Вам позвонил «сотрудник банка» и подтвердил подозрительную активность. Вы поверили?","options":[{"text":"Да, поверил","color":"red"},{"text":"Нет, перезвонил в банк сам","color":"green"}],"explain":{"red":"Мошенники используют украденные данные, чтобы убедить вас. Звонок от «безопасника» — следующий этап атаки.","green":"Главное правило безопасности: перезванивать в банк самостоятельно по номеру на карте. Только так вы убедитесь, что говорите с реальным сотрудником."}},{"id":4,"question":"Он попросил назвать последние 4 цифры вашей карты «для верификации». Вы назвали?","options":[{"text":"Да, назвал","color":"red"},{"text":"Нет, не назвал","color":"green"}],"explain":{"red":"Последние 4 цифры — часть полного номера карты. Этой информации достаточно для некоторых операций. Настоящий сотрудник никогда не спросит их.","green":"Верно. Любые данные карты — в том числе частичные — нельзя сообщать по телефону, если вы не уверены в собеседнике на 100%."}},{"id":5,"question":"Он сказал, что ваш счёт в опасности, и нужно срочно создать «безопасный счёт». Вы согласились?","options":[{"text":"Да, согласился","color":"red"},{"text":"Нет, понял обман","color":"green"}],"explain":{"red":"Понятия «безопасный счёт» не существует. Это уловка, чтобы вы сами перевели деньги мошенникам. Ни один банк не предлагает таких услуг.","green":"Прекрасно. Запомните: любые разговоры о «безопасных счетах» — стопроцентное мошенничество."}},{"id":6,"question":"Он попросил перевести все деньги на «безопасный счёт». Вы перевели?","options":[{"text":"Да, перевёл","color":"red"},{"text":"Нет, не перевёл","color":"green"}],"explain":{"red":"К сожалению, вы перевели деньги мошенникам. Обратитесь в банк и полицию немедленно. Шанс вернуть средства есть, если действовать быстро.","green":"Вы прошли сценарий, не потеряв деньги. Поздравляем! Теперь вы знаете главное: безопасных счетов не бывает, а сотрудники банков не просят переводов."}}],"verdicts":[{"minRed":0,"maxRed":1,"title":"Вы отлично защищены","text":"Вы почти не попались ни на одну уловку. Ваша финансовая грамотность на высоте. Поделитесь этим сценарием с друзьями и родственниками."},{"minRed":2,"maxRed":3,"title":"Есть над чем работать","text":"Вы прошли несколько шагов в красной зоне. Мошенники используют психологическое давление и спешку. Запомните: ни один банк не просит переводить деньги. «Безопасный счёт» — это миф."},{"minRed":4,"maxRed":6,"title":"Вы бы потеряли все деньги","text":"К сожалению, вы прошли почти все шаги жертвы. Мошенники очень убедительны, но теперь вы знаете схему. Главное: всегда перезванивайте в банк сами."}]},{"id":"government-compensation","pickerLabel":"Мне предложили компенсацию от государства, но нужно было заплатить пошлину","emoji":"💰","title":"Компенсация от государства","subtitle":"Проверьте, не попадётесь ли вы на обещание лёгких денег","description":"Вам сообщили о крупной денежной выплате, но нужно оплатить «пошлину». Проверьте, распознаете ли вы эту схему.","source":"По материалам мвд.рф и banki.ru","steps":[{"id":1,"question":"Вам пришло сообщение о крупной компенсации от государства. Вы перешли по ссылке?","options":[{"text":"Да, интересно же","color":"red"},{"text":"Нет, удалил","color":"green"}],"explain":{"red":"Сообщения о неожиданных компенсациях — классическая приманка. Государство не рассылает уведомления о выплатах через СМС.","green":"Правильное решение. Любые государственные выплаты оформляются через Госуслуги, МФЦ или официальные ведомства, а не через ссылки в СМС."}},{"id":2,"question":"На сайте нужно было оплатить «пошлину» для получения компенсации. Вы заплатили?","options":[{"text":"Да, заплатил","color":"red"},{"text":"Нет, это подозрительно","color":"green"}],"explain":{"red":"Компенсации не требуют предоплаты. Любой платёж перед получением выплаты — 100% мошенничество. Вы только что отдали свои деньги.","green":"Верно. Никакие госвыплаты не требуют «пошлин» и «комиссий» — налоги уже удержаны или выплата идёт полностью."}},{"id":3,"question":"«Сотрудник» сказал, что компенсация заморожена и нужен ещё один платёж для «разморозки». Вы заплатили снова?","options":[{"text":"Да, заплатил","color":"red"},{"text":"Нет, понял обман","color":"green"}],"explain":{"red":"Мошенники будут выманивать деньги снова и снова, придумывая новые причины. «Разморозка», «страховка», «налог» — всё это ложь.","green":"Отлично. Как только вас просят доплатить — это стопроцентный признак обмана. Настоящие выплаты не требуют повторных платежей."}},{"id":4,"question":"Вас попросили прислать фото паспорта для «верификации». Вы отправили?","options":[{"text":"Да, отправил","color":"red"},{"text":"Нет, отказался","color":"green"}],"explain":{"red":"Фото паспорта — ценный актив для мошенников. С ним можно оформить микрозаймы, зарегистрировать фирмы-однодневки и совершать другие преступления.","green":"Правильно. Паспортные данные нельзя отправлять незнакомцам. Для получения реальных госвыплат документы подаются лично или через проверенные порталы."}},{"id":5,"question":"Вам сказали, что для ускорения выплаты нужно установить приложение. Вы установили?","options":[{"text":"Да, установил","color":"red"},{"text":"Нет, отказался","color":"green"}],"explain":{"red":"Это приложение удалённого доступа. С его помощью мошенники получат полный доступ к вашему телефону, банку и контактам.","green":"Отлично. Запомните: любая просьба установить приложение от незнакомца — красный флаг. Устанавливайте приложения только из официальных магазинов."}},{"id":6,"question":"Вас попросили назвать код подтверждения из СМС. Вы назвали?","options":[{"text":"Да, назвал","color":"red"},{"text":"Нет, не назвал","color":"green"}],"explain":{"red":"Код из СМС — последний рубеж защиты ваших денег. Называя его, вы открываете мошенникам доступ к своим счетам. Код нельзя сообщать никому.","green":"Идеально. Вы прошли всю схему без потерь. Помните: коды из СМС, ПИН-коды и CVV нельзя называть никому и никогда. Даже сотрудникам банка."}}],"verdicts":[{"minRed":0,"maxRed":1,"title":"Вас не обмануть","text":"Вы распознали схему с самого начала. Обещание лёгких денег не сработало. Делитесь этим опытом с окружающими — чем больше людей знают, тем меньше жертв."},{"minRed":2,"maxRed":3,"title":"Вы могли бы попасться","text":"Вы прошли несколько шагов, поддавшись на уговоры. Мошенники давят на жадность и страх. Запомните: бесплатный сыр бывает только в мышеловке."},{"minRed":4,"maxRed":6,"title":"Вы бы потеряли деньги и данные","text":"Вы прошли почти все шаги жертвы. От фото паспорта до кода из СМС — мошенники получили бы всё. Будьте осторожны: государство никогда не просит предоплат."}]},{"id":"mom-accident","pickerLabel":"Мне позвонили и сказали, что близкий попал в беду","emoji":"😰","title":"Звонок о беде близкого","subtitle":"Проверьте, сможете ли вы сохранить хладнокровие","description":"Вам звонят и сообщают, что ваш родственник попал в ДТП или беду. Срочно нужны деньги. Проверьте, распознаете ли вы эту схему.","source":"По материалам мвд.рф","steps":[{"id":1,"question":"Вам позвонили с незнакомого номера и сказали, что ваш близкий попал в ДТП. Вы поверили?","options":[{"text":"Да, испугался","color":"red"},{"text":"Нет, усомнился","color":"green"}],"explain":{"red":"Мошенники давят на эмоции и страх за близких. Это классическая схема, которая работает, даже если человек обычно осторожен.","green":"Отлично. Первое правило: не паниковать. Даже если ситуация кажется критической — проверьте информацию."}},{"id":2,"question":"Звонящий представился сотрудником полиции и попросил деньги на «операцию» для родственника. Вы согласились помочь?","options":[{"text":"Да, согласился","color":"red"},{"text":"Нет, попросил время подумать","color":"green"}],"explain":{"red":"Полиция никогда не просит деньги по телефону. Это всегда мошенники. Даже если фоном слышны «голоса пострадавших» — это запись.","green":"Правильно. Любая просьба денег от «полиции» — красный флаг. Настоящие сотрудники оформляют всё документально."}},{"id":3,"question":"Вас попросили срочно перевести деньги на указанный счёт. Вы перевели?","options":[{"text":"Да, перевёл","color":"red"},{"text":"Нет, сначала позвонил родственнику","color":"green"}],"explain":{"red":"Вы только что отдали деньги мошенникам. Счёт принадлежит не больнице и не полиции, а преступникам.","green":"Гениально. Позвонить родственнику — единственное правильное действие. В 99% случаев с ним всё в порядке."}},{"id":4,"question":"Вам сказали не звонить родственнику, чтобы «не мешать операции». Вы послушались?","options":[{"text":"Да, послушался","color":"red"},{"text":"Нет, всё равно позвонил","color":"green"}],"explain":{"red":"Запрет на звонок близкому — главный признак мошенничества. Если бы ситуация была реальной, врачи бы сами связались с вами официально.","green":"Правильно. Мошенники всегда пытаются изолировать жертву от возможности проверить информацию."}},{"id":5,"question":"Вас попросили подтвердить перевод кодом из СМС. Вы подтвердили?","options":[{"text":"Да, подтвердил","color":"red"},{"text":"Нет, не стал","color":"green"}],"explain":{"red":"Код из СМС — подпись для списания. Называя его, вы разрешаете перевод денег. Никому и никогда не называйте коды.","green":"Верно. Код из СМС — последняя защита ваших денег. Его нельзя сообщать никому, даже «полиции»."}},{"id":6,"question":"Вам позвонили снова и попросили ещё денег на «адвоката». Вы перевели?","options":[{"text":"Да, перевёл ещё","color":"red"},{"text":"Нет, понял обман","color":"green"}],"explain":{"red":"Мошенники будут выманивать деньги, пока вы не поймёте обман или не закончатся средства. Помните: настоящая полиция не просит денег по телефону.","green":"Блестяще. Вы прошли схему, не попавшись. Запомните навсегда: если просят деньги за близкого — сначала позвоните ему."}}],"verdicts":[{"minRed":0,"maxRed":1,"title":"Хладнокровие — ваше оружие","text":"Вы не поддались панике и не дали себя обмануть. Мошенники рассчитывают на страх, но вы его победили. Расскажите об этой схеме пожилым родственникам — они в группе риска."},{"minRed":2,"maxRed":3,"title":"Вы были на грани","text":"Вы почти поверили, но что-то остановило. В реальной ситуации мошенники давят сильнее. Запомните правило: сначала проверь — потом плати."},{"minRed":4,"maxRed":6,"title":"Вы бы потеряли деньги","text":"Страх за близких — сильнейшая эмоция, и мошенники это используют. Запомните: никогда не переводите деньги, не проверив информацию. Сначала позвоните родственнику."}]},{"id":"gosuslugi-hack","pickerLabel":"Мне позвонили от оператора связи и попросили код из СМС","emoji":"📱","title":"Взлом через Госуслуги","subtitle":"Проверьте, защищены ли ваши аккаунты","description":"Мошенники получают доступ к Госуслугам через уловку с SIM-картой. Проверьте, сможете ли вы защитить свои данные.","source":"По материалам cbr.ru и mfc.ru","steps":[{"id":1,"question":"Вам позвонили от «оператора связи» и сказали, что вашу SIM-карту заменяют. Вы назвали код из СМС?","options":[{"text":"Да, назвал","color":"red"},{"text":"Нет, повесил трубку","color":"green"}],"explain":{"red":"Код из СМС — это подтверждение замены SIM-карты. Назвав его, вы передаёте свой номер мошенникам. Теперь все ваши СМС уходят им.","green":"Правильно. Операторы связи никогда не звонят с просьбой назвать код. Если нужна замена — вы сами обращаетесь в салон."}},{"id":2,"question":"Вам пришло уведомление о входе в Госуслуги с нового устройства. Вы не обратили внимания?","options":[{"text":"Да, проигнорировал","color":"red"},{"text":"Нет, сразу проверил","color":"green"}],"explain":{"red":"Уведомления от Госуслуг нельзя игнорировать. Если это не вы — срочно меняйте пароль. Мошенники уже вошли.","green":"Отлично. Любое уведомление о входе с нового устройства требует немедленной проверки. Это ваша первая линия обороны."}},{"id":3,"question":"Мошенники оформили кредит через Госуслуги. Вы не заметили подозрительных уведомлений?","options":[{"text":"Да, не заметил","color":"red"},{"text":"Нет, слежу за уведомлениями","color":"green"}],"explain":{"red":"Через Госуслуги можно оформить микрозаймы. Если вы не следите за уведомлениями, кредиты могут оформить без вашего ведома.","green":"Отлично. МФО проверяют кредитную историю через Госуслуги. Если вы видите лишние запросы — бейте тревогу."}},{"id":4,"question":"Вам позвонили из «банка» и сказали, что на ваше имя оформили кредит. Вы поверили?","options":[{"text":"Да, поверил","color":"red"},{"text":"Нет, перезвонил в банк сам","color":"green"}],"explain":{"red":"Это второй этап атаки. Мошенники уже знают о вас всё из Госуслуг и используют это, чтобы украсть деньги.","green":"Правильно. Всегда перезванивайте в банк сами по номеру с карты. Если кредит действительно оформили — банк поможет."}},{"id":5,"question":"Вам предложили перевести деньги на «безопасный счёт». Вы согласились?","options":[{"text":"Да, согласился","color":"red"},{"text":"Нет, отказался","color":"green"}],"explain":{"red":"Безопасных счетов не существует. Вы переводите деньги мошенникам на их реальный счёт.","green":"Верно. Любое упоминание «безопасного счёта» — признак мошенничества."}},{"id":6,"question":"Вы перевели все сбережения на «безопасный счёт»?","options":[{"text":"Да, перевёл","color":"red"},{"text":"Нет, не перевёл","color":"green"}],"explain":{"red":"К сожалению, вы перевели деньги мошенникам. Немедленно обратитесь в банк и полицию. Шанс вернуть есть, если действовать быстро.","green":"Вы прошли эту схему. Запомните главное: коды из СМС — только вам, и никогда никому их не называйте."}}],"verdicts":[{"minRed":0,"maxRed":1,"title":"Ваша цифровая гигиена на высоте","text":"Вы не попались ни на одном этапе. Внимательность к уведомлениям и знание основ безопасности спасли ваши данные и деньги."},{"minRed":2,"maxRed":3,"title":"Вы в группе риска","text":"Мошенники почти получили доступ к вашим данным. Настройте двухфакторную аутентификацию на Госуслугах и никогда не игнорируйте уведомления."},{"minRed":4,"maxRed":6,"title":"Ваши данные скомпрометированы","text":"Мошенники получили бы доступ к Госуслугам, оформили бы кредиты и украли деньги. Срочно настройте двухфакторную аутентификацию на всех сервисах."}]},{"id":"boss-telegram","pickerLabel":"Мне написал начальник в Telegram","emoji":"💼","title":"Фальшивый начальник в Telegram","subtitle":"Проверьте, сможете ли вы отказать руководству","description":"Вам пишет «руководитель» в мессенджере и просит срочно перевести деньги или предоставить данные. Проверьте свою бдительность.","source":"По материалам gazprombank.ru и mos.ru","steps":[{"id":1,"question":"Вам написал в Telegram человек с фото и именем вашего начальника. Вы ответили?","options":[{"text":"Да, ответил","color":"red"},{"text":"Нет, проигнорировал","color":"green"}],"explain":{"red":"Мошенники копируют аватарки и имена реальных сотрудников. Если вы ответили — вы уже в зоне риска.","green":"Правильно. Если начальник пишет в нерабочее время из неожиданного аккаунта — это повод насторожиться."}},{"id":2,"question":"Он сказал, что это «секретный разговор» и нужно срочно помочь с переводом. Вы согласились?","options":[{"text":"Да, согласился","color":"red"},{"text":"Нет, попросил подтвердить по телефону","color":"green"}],"explain":{"red":"«Секретно» и «срочно» — любимые слова мошенников. Они создают давление, чтобы вы не успели подумать.","green":"Отлично. Если начальник действительно просит — он сможет подтвердить это по телефону или лично."}},{"id":3,"question":"Он попросил перевести деньги для «срочной сделки» и обещал вернуть позже. Вы перевели?","options":[{"text":"Да, перевёл","color":"red"},{"text":"Нет, отказался","color":"green"}],"explain":{"red":"Вы перевели деньги мошенникам. Никакой сделки не существует, и деньги вам не вернут.","green":"Правильно. Руководитель не будет просить личные переводы через мессенджеры. Это всегда мошенничество."}},{"id":4,"question":"Он попросил прислать фото пропуска или документа. Вы отправили?","options":[{"text":"Да, отправил","color":"red"},{"text":"Нет, не отправил","color":"green"}],"explain":{"red":"Фото документов — ценная информация для мошенников. С ними можно оформить кредиты или использовать для других схем.","green":"Верно. Документы нельзя отправлять в мессенджерах по первой просьбе, даже если кажется, что просит руководитель."}},{"id":5,"question":"Он попросил подтвердить операцию кодом из СМС. Вы подтвердили?","options":[{"text":"Да, подтвердил","color":"red"},{"text":"Нет, не стал","color":"green"}],"explain":{"red":"Код из СМС — ваш ключ к деньгам. Назвав его, вы открываете мошенникам доступ к счетам.","green":"Правильно. Код из СМС нельзя называть никому — ни начальнику, ни коллеге, ни «сотруднику банка»."}},{"id":6,"question":"Он попросил ещё денег, сказав, что «сделка увеличилась». Вы перевели ещё?","options":[{"text":"Да, перевёл ещё","color":"red"},{"text":"Нет, понял обман","color":"green"}],"explain":{"red":"Мошенники будут просить снова и снова. Запомните: настоящее начальство не просит переводов через мессенджеры.","green":"Вы прошли схему. Запомните: если «начальник» пишет о деньгах — позвоните ему по рабочему телефону."}}],"verdicts":[{"minRed":0,"maxRed":1,"title":"Вас не обмануть авторитетом","text":"Вы не поддались на давление и проверили информацию. Даже если пишет «начальник» — вы сохраняете критическое мышление."},{"minRed":2,"maxRed":3,"title":"Вы могли попасться","text":"Вы почти поверили. Мошенники умело копируют стиль общения руководителей. Запомните: секретных сделок через Telegram не бывает."},{"minRed":4,"maxRed":6,"title":"Вы бы перевели деньги","text":"Авторитет начальника сыграл свою роль. Теперь вы знаете эту схему. Любая просьба о деньгах в мессенджере требует личного подтверждения."}]},{"id":"gazprom-invest","pickerLabel":"Я вложил деньги в инвестиционную платформу","emoji":"📈","title":"Фальшивые инвестиции","subtitle":"Проверьте, распознаете ли вы финансовую пирамиду","description":"Вам предложили сверхдоходные инвестиции. Проверьте, сможете ли вы отличить реальную платформу от мошеннической.","source":"По материалам cbr.ru и banki.ru","steps":[{"id":1,"question":"Вам предложили лёгкий заработок на инвестициях с доходностью 30% в месяц. Вы заинтересовались?","options":[{"text":"Да, звучит заманчиво","color":"red"},{"text":"Нет, это нереально","color":"green"}],"explain":{"red":"30% в месяц — это 360% годовых. Ни один легальный инструмент не даёт такой доходности. Это признак финансовой пирамиды.","green":"Отлично. Доходность выше 20-30% годовых — уже повод для проверки. Легальные инвестиции дают 5-15% годовых."}},{"id":2,"question":"Вы зарегистрировались на сайте «инвестиционной платформы». Вы внесли первый взнос?","options":[{"text":"Да, внёс 10 000 ₽","color":"red"},{"text":"Нет, решил проверить компанию","color":"green"}],"explain":{"red":"Мошенники создают красивые сайты с «лицензиями» и «лицензиями ЦБ». Но реквизиты ведут на подставные фирмы. Вы только что отдали деньги.","green":"Правильно. Проверьте компанию в реестре ЦБ (cbr.ru) и поищите отзывы. Скорее всего, вы найдёте предупреждения."}},{"id":3,"question":"Вам показали растущий график дохода и предложили внести ещё. Вы внесли ещё?","options":[{"text":"Да, внёс ещё","color":"red"},{"text":"Нет, попросил вывести прибыль","color":"green"}],"explain":{"red":"Графики в личном кабинете — просто цифры. Реальных торгов нет. Мошенники рисуют любую картинку, лишь бы вы внесли больше.","green":"Умное решение. Запросите вывод денег. Если платформа реальная — вы получите прибыль. Если нет — начнутся отговорки."}},{"id":4,"question":"Вас попросили установить приложение для удалённого доступа для «помощи в настройке». Вы установили?","options":[{"text":"Да, установил","color":"red"},{"text":"Нет, отказался","color":"green"}],"explain":{"red":"Это приложение даст мошенникам полный доступ к вашему банку. Они увидят коды, пароли и смогут украсть все деньги.","green":"Правильно. Ни одна инвестиционная платформа не требует удалённого доступа. Это всегда мошенничество."}},{"id":5,"question":"Вы захотели вывести прибыль, но нужно оплатить «налог» 13%. Вы заплатили?","options":[{"text":"Да, заплатил налог","color":"red"},{"text":"Нет, это уловка","color":"green"}],"explain":{"red":"Налоги платятся автоматически или через брокера, а не по ссылке от «платформы». Вы заплатили мошенникам ещё раз.","green":"Верно. Любая дополнительная плата за вывод — признак мошенничества. Налоги не платят перед выводом."}},{"id":6,"question":"Вас попросили назвать код из СМС для «подтверждения вывода». Вы назвали?","options":[{"text":"Да, назвал","color":"red"},{"text":"Нет, не назвал","color":"green"}],"explain":{"red":"Код из СМС — это подтверждение списания, а не вывода. Мошенники украдут остаток денег на карте.","green":"Блестяще. Вы прошли схему. Запомните: сверхдоходности не бывает, а налоги не платят перед выводом."}}],"verdicts":[{"minRed":0,"maxRed":1,"title":"Вас не обмануть деньгами","text":"Вы распознали признаки финансовой пирамиды. Обещания сверхдоходности на вас не действуют. Делитесь этим знанием с другими."},{"minRed":2,"maxRed":3,"title":"Вы могли потерять сбережения","text":"Желание заработать чуть не победило. Запомните: доходность выше 20% годовых — повод проверить компанию в реестре ЦБ."},{"minRed":4,"maxRed":6,"title":"Вы бы потеряли все вложения","text":"Мошенники прошли с вами всю схему — от первого взноса до кражи остатка через код из СМС. Инвестируйте только через лицензированных брокеров."}]},{"id":"avito-phishing","pickerLabel":"Мне прислали ссылку на оплату на Avito","emoji":"🛒","title":"Обман на Avito","subtitle":"Проверьте, защищены ли ваши сделки","description":"Покупатель просит подтвердить сделку по ссылке. Проверьте, сможете ли вы отличить настоящий сайт от поддельного.","source":"По материалам avito.ru и banki.ru","steps":[{"id":1,"question":"Вы продавали товар на Avito. «Покупатель» попросил прислать код для подтверждения. Вы прислали?","options":[{"text":"Да, прислал","color":"red"},{"text":"Нет, отказался","color":"green"}],"explain":{"red":"Код подтверждения от Avito — это ключ к вашему аккаунту. Прислав его, вы передаёте мошенникам доступ к профилю и объявлениям.","green":"Правильно. Код подтверждения нельзя передавать никому. Avito никогда не просит его через чат."}},{"id":2,"question":"Он сказал, что ссылка на оплату не открывается, и попросил перейти по другой. Вы перешли?","options":[{"text":"Да, перешёл","color":"red"},{"text":"Нет, это подозрительно","color":"green"}],"explain":{"red":"Ссылка ведёт на фишинговый сайт, внешне неотличимый от Avito. Все данные, которые вы введёте, уйдут мошенникам.","green":"Отлично. Все безопасные сделки на Avito проходят внутри платформы. Ссылки от «покупателей» — всегда риск."}},{"id":3,"question":"На поддельном сайте Avito вы ввели логин и пароль от своего аккаунта. Вы ввели?","options":[{"text":"Да, ввёл","color":"red"},{"text":"Нет, заметил подмену","color":"green"}],"explain":{"red":"Теперь мошенники имеют доступ к вашему аккаунту. Они могут менять объявления, писать покупателям от вашего имени и собирать данные.","green":"Отлично. Проверка URL — признак цифровой грамотности. Адрес Avito — только www.avito.ru, без лишних слов."}},{"id":4,"question":"Вас попросили ввести данные карты для получения оплаты. Вы ввели?","options":[{"text":"Да, ввёл","color":"red"},{"text":"Нет, это обман","color":"green"}],"explain":{"red":"Для получения денег на карту не нужно вводить её данные — достаточно номера карты. Запрос полных данных — признак фишинга.","green":"Правильно. Для перевода достаточно номера карты. Никогда не вводите CVV и срок действия на подозрительных сайтах."}},{"id":5,"question":"Пришёл код из СМС от банка. «Покупатель» попросил назвать его для подтверждения сделки. Вы назвали?","options":[{"text":"Да, назвал","color":"red"},{"text":"Нет, не назвал","color":"green"}],"explain":{"red":"Код из СМС от банка — это подтверждение списания. Назвав его, вы даёте согласие на перевод денег мошенникам.","green":"Верно. Код из СМС нельзя называть никому, даже если собеседник представляется покупателем или сотрудником Avito."}},{"id":6,"question":"Вы заметили списание денег со счёта. Что будете делать?","options":[{"text":"Надеюсь, что само пройдёт","color":"red"},{"text":"Срочно звоню в банк","color":"green"}],"explain":{"red":"Ждать нельзя. Чем быстрее вы обратитесь в банк, тем выше шанс вернуть деньги. Звоните на номер на карте немедленно.","green":"Правильно. Немедленный звонок в банк — единственный шанс остановить перевод. Также подайте заявление в полицию."}}],"verdicts":[{"minRed":0,"maxRed":1,"title":"Вы не попались на фишинг","text":"Вы отлично знаете, как работают мошенники на площадках объявлений. Делитесь этим опытом — особенно с теми, кто только начинает продавать онлайн."},{"minRed":2,"maxRed":3,"title":"Вы могли потерять доступ","text":"Вы почти попались. Мошенники на Avito — одни из самых активных. Запомните: все сделки только внутри площадки."},{"minRed":4,"maxRed":6,"title":"Вы бы потеряли деньги и аккаунт","text":"Мошенники провели бы вас по всей схеме: от кражи аккаунта до списания денег с карты. Будьте внимательны с ссылками от незнакомцев."}]}]');

